import{_ as e,c as o,o as t,ag as r}from"./chunks/framework.DPDPlp3K.js";const m=JSON.parse('{"title":"Package Structure","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://sqlrooms.org/packages.html"}]]},"headers":[],"relativePath":"packages.md","filePath":"packages.md"}'),i={name:"packages.md"};function s(n,a,l,d,c,p){return t(),o("div",null,a[0]||(a[0]=[r('<h1 id="package-structure" tabindex="-1">Package Structure <a class="header-anchor" href="#package-structure" aria-label="Permalink to &quot;Package Structure&quot;">​</a></h1><p>SQLRooms is organized into several packages that work together to provide a complete framework for building analytics applications.</p><h2 id="core-packages" tabindex="-1">Core Packages <a class="header-anchor" href="#core-packages" aria-label="Permalink to &quot;Core Packages&quot;">​</a></h2><h3 id="sqlrooms-project-builder" tabindex="-1"><a href="./api/project-builder/">@sqlrooms/project-builder</a> <a class="header-anchor" href="#sqlrooms-project-builder" aria-label="Permalink to &quot;[@sqlrooms/project-builder](./api/project-builder/index.md)&quot;">​</a></h3><p>Core framework package that provides the foundation for building analytics applications. It handles project state management using <a href="https://github.com/pmndrs/zustand" target="_blank" rel="noreferrer">Zustand</a> with a composable slice-based architecture, allowing applications to combine and extend functionality from different modules. The package integrates the panel system and includes DuckDB integration to keep track of database tables created as part of the project.</p><h3 id="sqlrooms-project-config" tabindex="-1"><a href="./api/project-config/">@sqlrooms/project-config</a> <a class="header-anchor" href="#sqlrooms-project-config" aria-label="Permalink to &quot;[@sqlrooms/project-config](./api/project-config/index.md)&quot;">​</a></h3><p>A central configuration and type definitions package that maintains base project configuration schemas and <a href="https://zod.dev/" target="_blank" rel="noreferrer">Zod</a> schema definitions. It provides TypeScript types and interfaces along with essential constants and utilities used throughout the framework.</p><h3 id="sqlrooms-duckdb" tabindex="-1"><a href="./api/duckdb/">@sqlrooms/duckdb</a> <a class="header-anchor" href="#sqlrooms-duckdb" aria-label="Permalink to &quot;[@sqlrooms/duckdb](./api/duckdb/index.md)&quot;">​</a></h3><p>A powerful DuckDB integration package that manages DuckDB-WASM instances and handles query execution. It provides robust data source connection capabilities and ensures type-safe query results for reliable data operations.</p><h3 id="sqlrooms-ui" tabindex="-1"><a href="./api/ui/">@sqlrooms/ui</a> <a class="header-anchor" href="#sqlrooms-ui" aria-label="Permalink to &quot;[@sqlrooms/ui](./api/ui/index.md)&quot;">​</a></h3><p>A comprehensive UI toolkit based on <a href="https://ui.shadcn.com/" target="_blank" rel="noreferrer">shadcn/ui</a> that provides shared components and styling utilities. It includes a carefully crafted Tailwind preset configuration, a library of common UI components, robust theme management capabilities, and a collection of icons and assets.</p><h2 id="feature-packages" tabindex="-1">Feature Packages <a class="header-anchor" href="#feature-packages" aria-label="Permalink to &quot;Feature Packages&quot;">​</a></h2><h3 id="sqlrooms-ai" tabindex="-1"><a href="./api/ai/">@sqlrooms/ai</a> <a class="header-anchor" href="#sqlrooms-ai" aria-label="Permalink to &quot;[@sqlrooms/ai](./api/ai/index.md)&quot;">​</a></h3><p>An AI integration package that enables natural language querying and analysis capabilities. It provides tools for query generation, result interpretation, and interactive AI-powered analytics workflows.</p><h3 id="sqlrooms-data-table" tabindex="-1"><a href="./api/data-table/">@sqlrooms/data-table</a> <a class="header-anchor" href="#sqlrooms-data-table" aria-label="Permalink to &quot;[@sqlrooms/data-table](./api/data-table/index.md)&quot;">​</a></h3><p>An advanced interactive data grid component designed for SQL query result visualization. The table supports dynamic column sorting and pagination features for efficient data exploration and analysis.</p><h3 id="sqlrooms-dropzone" tabindex="-1"><a href="./api/dropzone/">@sqlrooms/dropzone</a> <a class="header-anchor" href="#sqlrooms-dropzone" aria-label="Permalink to &quot;[@sqlrooms/dropzone](./api/dropzone/index.md)&quot;">​</a></h3><p>A comprehensive file upload solution that implements drag-and-drop functionality. It provides sophisticated file upload handling with built-in file type validation and upload progress tracking to enhance the user experience.</p><h3 id="sqlrooms-layout" tabindex="-1"><a href="./api/layout/">@sqlrooms/layout</a> <a class="header-anchor" href="#sqlrooms-layout" aria-label="Permalink to &quot;[@sqlrooms/layout](./api/layout/index.md)&quot;">​</a></h3><p>A sophisticated layout system and panel management solution based on <a href="https://nomcopter.github.io/react-mosaic/" target="_blank" rel="noreferrer">react-mosaic</a> that enables flexible panel layouts with intuitive sidebar and main view management. It supports smooth panel resize functionality and ensures layout persistence across sessions.</p><h3 id="sqlrooms-mosaic" tabindex="-1"><a href="./api/mosaic/">@sqlrooms/mosaic</a> <a class="header-anchor" href="#sqlrooms-mosaic" aria-label="Permalink to &quot;[@sqlrooms/mosaic](./api/mosaic/index.md)&quot;">​</a></h3><p>A visualization package that integrates with <a href="https://idl.uw.edu/mosaic/" target="_blank" rel="noreferrer">UW Interactive Data Lab&#39;s Mosaic library</a>. It provides declarative chart specifications and interactive visualization capabilities for data analysis.</p><h3 id="sqlrooms-s3-browser" tabindex="-1"><a href="./api/s3-browser/">@sqlrooms/s3-browser</a> <a class="header-anchor" href="#sqlrooms-s3-browser" aria-label="Permalink to &quot;[@sqlrooms/s3-browser](./api/s3-browser/index.md)&quot;">​</a></h3><p>A feature-rich S3-compatible storage browser that provides an intuitive file browsing interface. It supports file upload and download operations, comprehensive directory management, and seamless S3 bucket integration.</p><h3 id="sqlrooms-sql-editor" tabindex="-1"><a href="./api/sql-editor/">@sqlrooms/sql-editor</a> <a class="header-anchor" href="#sqlrooms-sql-editor" aria-label="Permalink to &quot;[@sqlrooms/sql-editor](./api/sql-editor/index.md)&quot;">​</a></h3><p>A powerful SQL query editor that enhances the development experience with syntax highlighting and intelligent auto-completion. It maintains a query history for easy reference and provides integrated result visualization capabilities.</p><h3 id="sqlrooms-cosmos" tabindex="-1"><a href="./api/cosmos/">@sqlrooms/cosmos</a> <a class="header-anchor" href="#sqlrooms-cosmos" aria-label="Permalink to &quot;[@sqlrooms/cosmos](./api/cosmos/index.md)&quot;">​</a></h3><p>A graph visualization package that integrates <a href="https://github.com/cosmograph-org/cosmos" target="_blank" rel="noreferrer">Cosmos</a> for creating interactive network visualizations. It provides high-performance WebGL-based graph rendering capabilities with support for large-scale networks. See <a href="/examples.html#cosmos-graph-visualization">Cosmos integration example</a>.</p><h3 id="sqlrooms-utils" tabindex="-1"><a href="./api/utils/">@sqlrooms/utils</a> <a class="header-anchor" href="#sqlrooms-utils" aria-label="Permalink to &quot;[@sqlrooms/utils](./api/utils/index.md)&quot;">​</a></h3><p>A utility package providing shared helper functions for color manipulation, data formatting, random generation, and string operations used across the framework.</p><h3 id="sqlrooms-vega" tabindex="-1"><a href="./api/vega/">@sqlrooms/vega</a> <a class="header-anchor" href="#sqlrooms-vega" aria-label="Permalink to &quot;[@sqlrooms/vega](./api/vega/index.md)&quot;">​</a></h3><p>A data visualization package that integrates <a href="https://vega.github.io/vega-lite/" target="_blank" rel="noreferrer">Vega-Lite</a> for creating sophisticated interactive visualizations. It provides React components for rendering Vega specifications and handling visualization interactions.</p>',32)]))}const u=e(i,[["render",s]]);export{m as __pageData,u as default};
